const items = $input.all();

// 1. Filtrar: solo los que cumplen TODAS las condiciones booleanas
const filtrados = items.filter(item => {
  const d = item.json;
  const followUpSent = d.follow_up_sent === true || d.follow_up_sent === 'true';
  const responded = d.responded === true || d.responded === 'true';
  const followUp2Sent = d.follow_up_2_sent === true || d.follow_up_2_sent === 'true';

  // Debe tener follow_up_sent=true, responded=false, follow_up_2_sent=false
  return followUpSent && !responded && !followUp2Sent;
});

console.log(`Total traídos: ${items.length}, Después de filtrar booleanos: ${filtrados.length}`);

if (filtrados.length === 0) return [];

// 2. Deduplicar por teléfono quedándose con el más reciente
const porTelefono = {};
for (const item of filtrados) {
  const phone = item.json.phone;
  if (!porTelefono[phone]) {
    porTelefono[phone] = item;
  } else {
    const actual = new Date(porTelefono[phone].json.last_bot_message_at);
    const nuevo = new Date(item.json.last_bot_message_at);
    if (nuevo > actual) {
      porTelefono[phone] = item;
    }
  }
}

// 3. Ordenar por follow_up_scheduled_at ascendente (el más viejo primero)
const deduplicados = Object.values(porTelefono);
deduplicados.sort((a, b) => {
  const fechaA = new Date(a.json.follow_up_scheduled_at || 0);
  const fechaB = new Date(b.json.follow_up_scheduled_at || 0);
  return fechaA - fechaB;
});

console.log(`Después de deduplicar: ${deduplicados.length}, Enviando: ${deduplicados[0]?.json?.phone}`);

// 4. Tomar SOLO el primero (1 por ejecución)
return [deduplicados[0]];

